let rawText = $input.first().json.snippet || $input.first().json.chatInput;
if (typeof rawText === 'string' && rawText.length > 0) {
  rawText = rawText.replace(/<[^>]*>/g, ''); // HTML রিমুভ
  rawText = rawText.replace(/--\s*[\s\S]*$/, ''); // সিগনেচার কাটা
  rawText = rawText.replace(/\s+/g, ' ').trim(); // এক্সট্রা স্পেস ট্রিম
}
return { json: { optimized_text: rawText } };

